  ?song wdt:P31 wd:Q1720909 ;
         rdfs:label ?songLabel.
  FILTER (lang(?songLabel) = 'en' && regex(?songLabel, "swingin' on a star", "i"))
  ?tvshow wdt:P31 wd:Q149158 ;
          wdt:P1875 ?song.
  ?tvshow rdfs:label ?tvshowLabel.
  FILTER (lang(?tvshowLabel) = 'en')
}

